const pptxgen = require("pptxgenjs");

const pres = new pptxgen();
pres.layout = "LAYOUT_16x9";
pres.title = "AX CoE 킥오프";

// Color palette: deep navy dominant, teal accent, off-white
const C = {
  navy: "1B2A4A",
  navyMid: "243358",
  teal: "0D9488",
  tealLight: "CCFBF1",
  tealMid: "14B8A6",
  white: "FFFFFF",
  offWhite: "F8F9FB",
  gray100: "F1F5F9",
  gray400: "94A3B8",
  gray600: "475569",
  gray800: "1E293B",
  amber: "D97706",
  amberLight: "FEF3C7",
  purple: "6D28D9",
  purpleLight: "EDE9FE",
  coral: "DC2626",
  coralLight: "FEE2E2",
};

// ─────────────────────────────────────────────────────────
// SLIDE 1: TITLE
// ─────────────────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.navy };

  // Left accent bar
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 0.18, h: 5.625,
    fill: { color: C.teal }, line: { type: "none" }
  });

  // Teal top stripe (partial)
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.18, y: 0, w: 9.82, h: 0.06,
    fill: { color: C.teal }, line: { type: "none" }
  });

  // Date badge
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 0.55, w: 2.1, h: 0.32,
    fill: { color: C.tealMid, transparency: 80 }, line: { type: "none" }
  });
  s.addText("2026년 1월 킥오프", {
    x: 0.5, y: 0.55, w: 2.1, h: 0.32,
    fontSize: 9, color: C.tealLight, align: "center", valign: "middle",
    fontFace: "Calibri", margin: 0
  });

  // Main title
  s.addText("AX CoE 킥오프", {
    x: 0.5, y: 1.15, w: 9, h: 1.1,
    fontSize: 48, bold: true, color: C.white, fontFace: "Calibri",
    align: "left", valign: "middle"
  });

  // Subtitle
  s.addText("AI가 일하는 방식이 되는 조직을 설계한다", {
    x: 0.5, y: 2.35, w: 9, h: 0.5,
    fontSize: 18, color: C.tealMid, fontFace: "Calibri",
    align: "left", valign: "middle"
  });

  // Divider
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 3.0, w: 9, h: 0.03,
    fill: { color: C.teal, transparency: 60 }, line: { type: "none" }
  });

  // Three info items
  const items = [
    { label: "주관", val: "EXG팀 AX CoE" },
    { label: "대상", val: "EXG팀 전원 + 유관 리더" },
    { label: "목표", val: "2026 AX 내재화 임계점 설계" },
  ];
  items.forEach((it, i) => {
    const x = 0.5 + i * 3.2;
    s.addText(it.label, {
      x, y: 3.2, w: 3.0, h: 0.25,
      fontSize: 9, color: C.gray400, fontFace: "Calibri", margin: 0
    });
    s.addText(it.val, {
      x, y: 3.42, w: 3.0, h: 0.3,
      fontSize: 12, color: C.white, bold: true, fontFace: "Calibri", margin: 0
    });
  });

  // Bottom bar
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 5.3, w: 10, h: 0.325,
    fill: { color: C.teal, transparency: 85 }, line: { type: "none" }
  });
  s.addText("LG PRI · EXG팀 AX CoE", {
    x: 0.5, y: 5.3, w: 9, h: 0.325,
    fontSize: 9, color: C.gray400, fontFace: "Calibri",
    align: "right", valign: "middle"
  });
}

// ─────────────────────────────────────────────────────────
// SLIDE 2: 오늘의 아젠다
// ─────────────────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.offWhite };

  // Header bar
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 10, h: 0.85,
    fill: { color: C.navy }, line: { type: "none" }
  });
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 0.18, h: 0.85,
    fill: { color: C.teal }, line: { type: "none" }
  });
  s.addText("오늘의 아젠다", {
    x: 0.35, y: 0, w: 9.5, h: 0.85,
    fontSize: 20, bold: true, color: C.white, fontFace: "Calibri",
    valign: "middle"
  });

  // Agenda items
  const agenda = [
    { time: "00:00 — 00:10", title: "Why Now", sub: "지금 AX 내재화를 해야 하는 이유" },
    { time: "00:10 — 00:25", title: "What We Build", sub: "AX CoE 역할과 2026 청사진" },
    { time: "00:25 — 00:40", title: "The Roadmap", sub: "임계점 설계 4단계 실행 계획" },
    { time: "00:40 — 00:50", title: "First Wins", sub: "Q1 즉시 실행 과제 3가지" },
    { time: "00:50 — 01:00", title: "Open Discussion", sub: "질의응답 및 공식 선언" },
  ];

  agenda.forEach((a, i) => {
    const y = 1.05 + i * 0.87;
    // Number circle
    s.addShape(pres.shapes.OVAL, {
      x: 0.35, y: y + 0.08, w: 0.42, h: 0.42,
      fill: { color: i === 0 ? C.teal : C.navy }, line: { type: "none" }
    });
    s.addText(String(i + 1), {
      x: 0.35, y: y + 0.08, w: 0.42, h: 0.42,
      fontSize: 13, bold: true, color: C.white, fontFace: "Calibri",
      align: "center", valign: "middle", margin: 0
    });

    // Time badge
    s.addShape(pres.shapes.RECTANGLE, {
      x: 0.9, y: y + 0.1, w: 1.55, h: 0.26,
      fill: { color: C.gray100 }, line: { type: "none" }
    });
    s.addText(a.time, {
      x: 0.9, y: y + 0.1, w: 1.55, h: 0.26,
      fontSize: 8.5, color: C.gray600, fontFace: "Calibri",
      align: "center", valign: "middle", margin: 0
    });

    // Title & sub
    s.addText(a.title, {
      x: 2.6, y: y, w: 7.2, h: 0.3,
      fontSize: 14, bold: true, color: C.gray800, fontFace: "Calibri", margin: 0
    });
    s.addText(a.sub, {
      x: 2.6, y: y + 0.3, w: 7.2, h: 0.26,
      fontSize: 11, color: C.gray600, fontFace: "Calibri", margin: 0
    });

    // Divider (not last)
    if (i < agenda.length - 1) {
      s.addShape(pres.shapes.LINE, {
        x: 0.35, y: y + 0.75, w: 9.3, h: 0,
        line: { color: C.gray400, width: 0.5, transparency: 60 }
      });
    }
  });
}

// ─────────────────────────────────────────────────────────
// SLIDE 3: WHY NOW — 임계점의 긴박성
// ─────────────────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.navy };

  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 0.18, h: 5.625,
    fill: { color: C.teal }, line: { type: "none" }
  });
  s.addText("Why Now", {
    x: 0.35, y: 0.3, w: 9.3, h: 0.55,
    fontSize: 24, bold: true, color: C.white, fontFace: "Calibri"
  });
  s.addText("지금 시작하지 않으면 격차는 기하급수적으로 벌어진다", {
    x: 0.35, y: 0.85, w: 9.3, h: 0.3,
    fontSize: 12, color: C.tealMid, fontFace: "Calibri"
  });

  // Three stat cards
  const stats = [
    { val: "88%", label: "기업이 AI를 최소\n1개 기능에 활용", src: "McKinsey 2025" },
    { val: "1%", label: "AI를 실제\n전사 통합한 기업", src: "McKinsey 2025" },
    { val: "88%", label: "AI 프로젝트가\n파일럿에서 멈춤", src: "IDC" },
  ];
  stats.forEach((st, i) => {
    const x = 0.35 + i * 3.15;
    s.addShape(pres.shapes.RECTANGLE, {
      x, y: 1.4, w: 3.0, h: 2.1,
      fill: { color: C.navyMid }, line: { color: C.teal, width: 0.5, transparency: 60 }
    });
    s.addText(st.val, {
      x, y: 1.5, w: 3.0, h: 0.95,
      fontSize: 52, bold: true, color: C.tealMid, fontFace: "Calibri",
      align: "center", valign: "bottom"
    });
    s.addText(st.label, {
      x, y: 2.5, w: 3.0, h: 0.65,
      fontSize: 11, color: C.white, fontFace: "Calibri",
      align: "center", valign: "middle"
    });
    s.addText(st.src, {
      x, y: 3.2, w: 3.0, h: 0.22,
      fontSize: 8, color: C.gray400, fontFace: "Calibri", align: "center"
    });
  });

  // Key message
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.35, y: 3.8, w: 9.3, h: 0.8,
    fill: { color: C.teal, transparency: 85 }, line: { type: "none" }
  });
  s.addText("격차는 기술이 아니라 조직·사람·프로세스에서 만들어진다. AX CoE는 그 격차를 설계로 닫는다.", {
    x: 0.35, y: 3.8, w: 9.3, h: 0.8,
    fontSize: 13, color: C.white, fontFace: "Calibri",
    align: "center", valign: "middle", italic: true
  });
}

// ─────────────────────────────────────────────────────────
// SLIDE 4: AX CoE 역할 — What We Build
// ─────────────────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.offWhite };

  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 10, h: 0.85,
    fill: { color: C.navy }, line: { type: "none" }
  });
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 0.18, h: 0.85,
    fill: { color: C.teal }, line: { type: "none" }
  });
  s.addText("What We Build  —  AX CoE의 역할", {
    x: 0.35, y: 0, w: 9.3, h: 0.85,
    fontSize: 20, bold: true, color: C.white, fontFace: "Calibri", valign: "middle"
  });

  // 4 function cards in 2x2
  const funcs = [
    { title: "전략·거버넌스", body: "도구 표준 수립, 유스케이스 라이브러리 관리, AI 정책 가이드라인", color: C.navy },
    { title: "인프라 지원", body: "M365 접근 환경, SharePoint 데이터 거버넌스, Power Automate 템플릿", color: C.teal },
    { title: "역량 개발", body: "Vibe-Coding 교육, Champion 네트워크, 모두의 AX 인증 체계", color: C.navy },
    { title: "성과 측정", body: "AX 성숙도 대시보드, Pulse Check 연계, 생산성 KPI 추적", color: C.teal },
  ];
  funcs.forEach((fn, i) => {
    const col = i % 2;
    const row = Math.floor(i / 2);
    const x = 0.35 + col * 4.75;
    const y = 1.1 + row * 2.1;
    s.addShape(pres.shapes.RECTANGLE, {
      x, y, w: 4.55, h: 1.9,
      fill: { color: C.white }, line: { color: C.gray400, width: 0.3, transparency: 50 }
    });
    // Left accent
    s.addShape(pres.shapes.RECTANGLE, {
      x, y, w: 0.06, h: 1.9,
      fill: { color: fn.color }, line: { type: "none" }
    });
    s.addText(fn.title, {
      x: x + 0.15, y: y + 0.18, w: 4.25, h: 0.32,
      fontSize: 14, bold: true, color: C.gray800, fontFace: "Calibri", margin: 0
    });
    s.addText(fn.body, {
      x: x + 0.15, y: y + 0.58, w: 4.25, h: 1.1,
      fontSize: 11, color: C.gray600, fontFace: "Calibri", margin: 0, lineSpacingMultiple: 1.3
    });
  });

  // Center node label
  s.addShape(pres.shapes.OVAL, {
    x: 4.25, y: 2.35, w: 1.5, h: 0.85,
    fill: { color: C.teal }, line: { type: "none" }
  });
  s.addText("AX CoE", {
    x: 4.25, y: 2.35, w: 1.5, h: 0.85,
    fontSize: 11, bold: true, color: C.white, fontFace: "Calibri",
    align: "center", valign: "middle", margin: 0
  });
}

// ─────────────────────────────────────────────────────────
// SLIDE 5: 2026 로드맵 — The Roadmap
// ─────────────────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.navy };

  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 0.18, h: 5.625,
    fill: { color: C.teal }, line: { type: "none" }
  });
  s.addText("The Roadmap  —  임계점까지 4단계", {
    x: 0.35, y: 0.3, w: 9.3, h: 0.5,
    fontSize: 22, bold: true, color: C.white, fontFace: "Calibri"
  });

  const phases = [
    { label: "Phase 1", period: "Q1  1~3월", title: "기반 구축", body: "인프라·CoE·정체성 프레이밍", color: "534AB7" },
    { label: "Phase 2", period: "Q2  4~6월", title: "첫 성공 경험", body: "Vibe-Coding 1기·Champion 선발", color: C.teal },
    { label: "Phase 3", period: "Q3  7~9월", title: "사회적 전염", body: "Show-and-Tell·대시보드 공개", color: C.amber },
    { label: "Phase 4", period: "Q4 10~12월", title: "임계점 도달", body: "KPI 달성·PoC 문서화", color: "DC2626" },
  ];

  // Timeline line
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.35, y: 3.1, w: 9.3, h: 0.04,
    fill: { color: C.teal, transparency: 60 }, line: { type: "none" }
  });

  phases.forEach((ph, i) => {
    const x = 0.35 + i * 2.35;
    const w = 2.15;

    // Card
    s.addShape(pres.shapes.RECTANGLE, {
      x, y: 1.05, w, h: 2.0,
      fill: { color: C.navyMid }, line: { color: ph.color, width: 0.7 }
    });
    // Top accent
    s.addShape(pres.shapes.RECTANGLE, {
      x, y: 1.05, w, h: 0.06,
      fill: { color: ph.color }, line: { type: "none" }
    });

    s.addText(ph.label, {
      x, y: 1.16, w, h: 0.25,
      fontSize: 9, color: ph.color, fontFace: "Calibri", bold: true,
      align: "center", margin: 0
    });
    s.addText(ph.period, {
      x, y: 1.38, w, h: 0.22,
      fontSize: 9, color: C.gray400, fontFace: "Calibri",
      align: "center", margin: 0
    });
    s.addText(ph.title, {
      x, y: 1.7, w, h: 0.35,
      fontSize: 14, bold: true, color: C.white, fontFace: "Calibri",
      align: "center", margin: 0
    });
    s.addText(ph.body, {
      x, y: 2.12, w, h: 0.7,
      fontSize: 10, color: C.gray400, fontFace: "Calibri",
      align: "center", margin: 0
    });

    // Timeline dot
    s.addShape(pres.shapes.OVAL, {
      x: x + w/2 - 0.14, y: 3.0, w: 0.28, h: 0.28,
      fill: { color: ph.color }, line: { type: "none" }
    });
  });

  // Bottom KPI row
  const kpis = ["교육 과정 6개", "LV3+ 30명 Pool", "생산성 +10%", "AX 성숙도 +15%p"];
  kpis.forEach((kpi, i) => {
    const x = 0.35 + i * 2.35;
    s.addText(kpi, {
      x, y: 3.55, w: 2.15, h: 0.3,
      fontSize: 9.5, color: C.tealLight, fontFace: "Calibri",
      align: "center", valign: "middle"
    });
  });

  // Arrow connectors between phases
  for (let i = 0; i < 3; i++) {
    const ax = 0.35 + i * 2.35 + 2.15;
    s.addShape(pres.shapes.RECTANGLE, {
      x: ax, y: 2.0, w: 0.2, h: 0.04,
      fill: { color: C.tealMid }, line: { type: "none" }
    });
  }
}

// ─────────────────────────────────────────────────────────
// SLIDE 6: FIRST WINS — Q1 즉시 실행 3가지
// ─────────────────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.offWhite };

  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 10, h: 0.85,
    fill: { color: C.navy }, line: { type: "none" }
  });
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 0.18, h: 0.85,
    fill: { color: C.teal }, line: { type: "none" }
  });
  s.addText("First Wins  —  Q1 즉시 실행 과제", {
    x: 0.35, y: 0, w: 9.3, h: 0.85,
    fontSize: 20, bold: true, color: C.white, fontFace: "Calibri", valign: "middle"
  });

  const wins = [
    {
      num: "01",
      title: "AX 베이스라인 진단",
      deadline: "1월 말까지",
      tasks: ["팀별 AI 도구 사용 현황 조사", "심리적 장벽·마찰 지점 파악", "Pulse Check에 AX 문항 탑재"],
      color: C.teal
    },
    {
      num: "02",
      title: "원클릭 유스케이스 3개 탑재",
      deadline: "2월 중순까지",
      tasks: ["회의록 AI 자동화 (Teams)", "보고서 초안 생성 (Copilot)", "설문 분석 자동화 (Power Automate)"],
      color: "534AB7"
    },
    {
      num: "03",
      title: "CoE 유스케이스 라이브러리",
      deadline: "3월 말까지",
      tasks: ["업무별 AI 활용 가이드 초안 작성", "SharePoint 내 공식 게시", "Champion 1기 후보군 사전 식별"],
      color: C.amber
    },
  ];

  wins.forEach((w, i) => {
    const x = 0.35 + i * 3.1;
    const cardW = 2.95;

    s.addShape(pres.shapes.RECTANGLE, {
      x, y: 1.0, w: cardW, h: 4.3,
      fill: { color: C.white }, line: { color: C.gray400, width: 0.3, transparency: 50 }
    });
    // Top accent bar
    s.addShape(pres.shapes.RECTANGLE, {
      x, y: 1.0, w: cardW, h: 0.08,
      fill: { color: w.color }, line: { type: "none" }
    });

    // Number
    s.addText(w.num, {
      x, y: 1.12, w: cardW, h: 0.7,
      fontSize: 40, bold: true, color: w.color, fontFace: "Calibri",
      align: "center", valign: "middle"
    });

    // Title
    s.addText(w.title, {
      x: x + 0.15, y: 1.92, w: cardW - 0.3, h: 0.55,
      fontSize: 13, bold: true, color: C.gray800, fontFace: "Calibri",
      align: "center", valign: "middle"
    });

    // Deadline badge
    s.addShape(pres.shapes.RECTANGLE, {
      x: x + 0.4, y: 2.58, w: cardW - 0.8, h: 0.28,
      fill: { color: w.color, transparency: 85 }, line: { type: "none" }
    });
    s.addText(w.deadline, {
      x: x + 0.4, y: 2.58, w: cardW - 0.8, h: 0.28,
      fontSize: 9.5, color: w.color, fontFace: "Calibri",
      align: "center", valign: "middle", bold: true, margin: 0
    });

    // Divider
    s.addShape(pres.shapes.LINE, {
      x: x + 0.15, y: 3.0, w: cardW - 0.3, h: 0,
      line: { color: C.gray400, width: 0.4, transparency: 60 }
    });

    // Tasks
    w.tasks.forEach((task, ti) => {
      s.addText([
        { text: "· ", options: { color: w.color, bold: true } },
        { text: task, options: { color: C.gray600 } }
      ], {
        x: x + 0.15, y: 3.1 + ti * 0.38, w: cardW - 0.3, h: 0.36,
        fontSize: 10.5, fontFace: "Calibri", valign: "middle"
      });
    });
  });
}

// ─────────────────────────────────────────────────────────
// SLIDE 7: 공식 선언 & 토론
// ─────────────────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.navy };

  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 0.18, h: 5.625,
    fill: { color: C.teal }, line: { type: "none" }
  });
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 10, h: 0.06,
    fill: { color: C.teal }, line: { type: "none" }
  });

  // Main declaration
  s.addText("우리는 오늘부터", {
    x: 0.35, y: 0.7, w: 9.3, h: 0.55,
    fontSize: 16, color: C.gray400, fontFace: "Calibri", align: "center"
  });
