const fs = require("fs");

// ── 색상 팔레트
const C = {
  navy:    "1B2A4A",
  teal:    "0D9488",
  tealLt:  "CCFBF1",
  gray100: "F8FAFC",
  gray200: "E2E8F0",
  gray400: "94A3B8",
  gray600: "475569",
  gray800: "1E293B",
  amber:   "D97706",
  amberLt: "FFFBEB",
  coral:   "DC2626",
  coralLt: "FEF2F2",
  purple:  "7C3AED",
  purpleLt:"F5F3FF",
  white:   "FFFFFF",
};

// ── 공통 border
const cellBorder = (color = C.gray200) => ({
  top:    { style: BorderStyle.SINGLE, size: 1, color },
  bottom: { style: BorderStyle.SINGLE, size: 1, color },
  left:   { style: BorderStyle.SINGLE, size: 1, color },
  right:  { style: BorderStyle.SINGLE, size: 1, color },
});
const noBorder = {
  top:    { style: BorderStyle.NONE, size: 0, color: "FFFFFF" },
  bottom: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" },
  left:   { style: BorderStyle.NONE, size: 0, color: "FFFFFF" },
  right:  { style: BorderStyle.NONE, size: 0, color: "FFFFFF" },
};
const cellPad = { top: 100, bottom: 100, left: 140, right: 140 };

// ── 헬퍼: 섹션 헤더 단락 (teal accent)
function sectionHeader(text, level = 1) {
  const sizes = { 1: 32, 2: 26, 3: 22 };
  const hlevel = { 1: HeadingLevel.HEADING_1, 2: HeadingLevel.HEADING_2, 3: HeadingLevel.HEADING_3 };
  return new Paragraph({
    heading: hlevel[level],
    children: [new TextRun({ text, bold: true, color: C.navy, size: sizes[level], font: "Arial" })],
    spacing: { before: level === 1 ? 400 : 280, after: 160 },
    border: level === 1 ? { bottom: { style: BorderStyle.SINGLE, size: 4, color: C.teal, space: 4 } } : {},
  });
}

// ── 헬퍼: 일반 본문 단락
function body(text, { color = C.gray800, italic = false, bold = false, size = 22 } = {}) {
  return new Paragraph({
    children: [new TextRun({ text, color, italic, bold, size, font: "Arial" })],
    spacing: { after: 120 },
  });
}

// ── 헬퍼: 레이블+값 인라인
function labelVal(label, val, valColor = C.navy) {
  return new Paragraph({
    children: [
      new TextRun({ text: label + "  ", bold: true, color: C.gray600, size: 20, font: "Arial" }),
      new TextRun({ text: val, color: valColor, size: 20, font: "Arial" }),
    ],
    spacing: { after: 80 },
  });
}

// ── 헬퍼: 채워진 셀
function filledCell(text, fill, textColor = C.white, w = 2340, bold = false) {
  return new TableCell({
    borders: cellBorder(fill),
    shading: { fill, type: ShadingType.CLEAR },
    margins: cellPad,
    width: { size: w, type: WidthType.DXA },
    children: [new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ text, bold, color: textColor, size: 20, font: "Arial" })],
    })],
  });
}

// ── 헬퍼: 일반 셀
function plainCell(text, w, fill = C.white, textColor = C.gray800, bold = false) {
  return new TableCell({
    borders: cellBorder(),
    shading: { fill, type: ShadingType.CLEAR },
    margins: cellPad,
    width: { size: w, type: WidthType.DXA },
    children: [new Paragraph({
      children: [new TextRun({ text, color: textColor, size: 20, font: "Arial", bold })],
    })],
  });
}

// ── 헬퍼: 빈 줄
const gap = (n = 1) => Array.from({ length: n }, () =>
  new Paragraph({ children: [new TextRun("")], spacing: { after: 60 } })
);

// ── 헬퍼: 불릿 항목
function bullet(text, color = C.gray800) {
  return new Paragraph({
    numbering: { reference: "bullets", level: 0 },
    children: [new TextRun({ text, color, size: 20, font: "Arial" })],
    spacing: { after: 80 },
  });
}

// ── 헬퍼: 강조 박스 (1열 테이블)
function calloutBox(text, fill = C.tealLt, textColor = C.teal, borderColor = C.teal) {
