{"language": "javascript", "code": "const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, HeadingLevel, BorderStyle,
  WidthType, ShadingType, VerticalAlign, PageNumber, LevelFormat,
  TabStopType, TabStopPosition, PageBreak
} = require("docx");
const fs = require("fs");

// ── 색상
const C = {
  navy:    "1B2A4A",
  teal:    "0D9488",
  tealLt:  "CCFBF1",
  tealM:   "5DCAA5",
  purple:  "6D28D9",
  purpleLt:"EDE9FE",
  amber:   "D97706",
  amberLt: "FEF3C7",
  coral:   "DC2626",
  coralLt: "FEE2E2",
  green:   "15803D",
  greenLt: "DCFCE7",
  gray100: "F8FAFC",
  gray200: "E2E8F0",
  gray400: "94A3B8",
  gray600: "475569",
  gray800: "1E293B",
  white:   "FFFFFF",
};

// ── 공통 border
const bSingle = (color = C.gray200) => ({ style: BorderStyle.SINGLE, size: 1, color });
const bThick  = (color = C.teal)   => ({ style: BorderStyle.THICK,  size: 6, color });
const bNone   = ()                  => ({ style: BorderStyle.NONE,   size: 0, color: C.white });
const allBorder= (color = C.gray200) => ({
  top: bSingle(color), bottom: bSingle(color),
  left: bSingle(color), right: bSingle(color)
});
const noBorder = () => ({
  top: bNone(), bottom: bNone(), left: bNone(), right: bNone()
});
const leftAccent = (color = C.teal) => ({
  top: bNone(), bottom: bNone(), right: bNone(),
  left: { style: BorderStyle.THICK, size: 16, color }
});

const pad = (v=80,h=120) => ({ top: v, bottom: v, left: h, right: h });

// ── 헬퍼
function P(children, opts = {}) {
  return new Paragraph({ children, ...opts });
}
function T(text, { bold=false, color=C.gray800, size=20, italic=false, font="Arial" }={}) {
  return new TextRun({ text, bold, color, size, italic, font });
}
function gap(n=1) {
  return Array.from({length:n}, ()=> P([T("","")], { spacing:{after:60} }));
}
function divLine(color=C.teal) {
  return P([T("")], {
    border: { bottom: { style: BorderStyle.SINGLE, size: 3, color, space: 3 } },
    spacing: { before: 100, after: 200 }
  });
}
function sectionTitle(text, color=C.navy, bgColor=null) {
  return P([T(text, { bold:true, color: bgColor ? C.white : color, size: 26 })], {
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 360, after: 160 },
    shading: bgColor ? { fill: bgColor, type: ShadingType.CLEAR } : undefined,
  });
}
function subTitle(text, color=C.teal) {
  return P([T(text, { bold:true, color, size: 22 })], {
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 240, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 2, color, space: 2 } }
  });
}
function h3(text, color=C.navy) {
  return P([T(text, { bold:true, color, size: 20 })], {
    heading: HeadingLevel.HEADING_3,
    spacing: { before: 180, after: 80 }
  });
}
function body(text, { color=C.gray800, italic=false, size=20 }={}) {
  return P([T(text, { color, italic, size })], { spacing: { after: 100 } });
}
function bul(text, color=C.gray800, indent=720) {
  return P([T(text, { color, size: 20 })], {
    numbering: { reference:"bullets", level:0 },
    spacing: { after: 80 },
    indent: { left: indent }
  });
}
function num(text, color=C.gray800) {
  return P([T(text, { color, size: 20 })], {
    numbering: { reference:"numbers", level:0 },
    spacing: { after: 80 }
  });
}

// ── 테이블 셀 헬퍼
function hCell(text, w, bg=C.navy, fg=C.white, span=1, vAlign=VerticalAlign.CENTER) {
  return new TableCell({
    columnSpan: span,
    borders: allBorder(bg),
    shading: { fill: bg, type: ShadingType.CLEAR },
    margins: pad(80,120),
    width: { size: w, type: WidthType.DXA },
    verticalAlign: vAlign,
    children: [P([T(text, { bold:true, color:fg, size:19 })], { alignment: AlignmentType.CENTER })]
  });
}
function dCell(text, w, bg=C.white, fg=C.gray800, h_align=AlignmentType.LEFT, wrap=false) {
  return new TableCell({
    borders: allBorder(),
    shading: { fill: bg, type: ShadingType.CLEAR },
    margins: pad(80,120),
    width: { size: w, type: WidthType.DXA },
    verticalAlign: VerticalAlign.CENTER,
    children: [P([T(text, { color:fg, size:19 })], {
      alignment: h_align,
      spacing: { after: 0 }
    })]
  });
}
function dCellMulti(paragraphs, w, bg=C.white) {
  return new TableCell({
    borders: allBorder(),
    shading: { fill: bg, type: ShadingType.CLEAR },
    margins: pad(80,120),
    width: { size: w, type: WidthType.DXA },
    verticalAlign: VerticalAlign.TOP,
    children: paragraphs
  });
}
function callout(text, bg=C.tealLt, borderColor=C.teal, textColor=C.teal) {
  return new Table({
    width: { size: 9026, type: WidthType.DXA },
    columnWidths: [9026],
    rows: [new TableRow({ children: [new TableCell({
      borders: {
        top: bSingle(borderColor), bottom: bSingle(borderColor),
        right: bSingle(borderColor),
        left: { style: BorderStyle.THICK, size: 20, color: borderColor }
      },
      shading: { fill: bg, type: ShadingType.CLEAR },
      margins: { top: 120, bottom: 120, left: 200, right: 120 },
      width: { size: 9026, type: WidthType.DXA },
      children: [P([T(text, { color: textColor, size: 19, italic: true })], { spacing:{after:0} })]
    })]})],
  });
}
function kpiTable(rows) {
  return new Table({
    width: { size: 9026, type: WidthType.DXA },
    columnWidths: [2200, 2000, 2000, 1426, 1400],
    rows: [
      new TableRow({ children: [
