      ]}),
      ...rows.map((r, i) => new TableRow({ children: [
        dCell(r[0], 2200, i%2?C.white:C.gray100, C.gray800),
        dCell(r[1], 2000, i%2?C.white:C.gray100, C.teal, AlignmentType.CENTER),
        dCell(r[2], 2000, i%2?C.white:C.gray100),
        dCell(r[3], 1426, i%2?C.white:C.gray100, C.gray600, AlignmentType.CENTER),
        dCell(r[4], 1400, i%2?C.white:C.gray100, C.gray600, AlignmentType.CENTER),
      ]}))
    ]
  });
}

// ════════════════════════════════════════════════════════════
// 문서 조립
